const item = $input.first().json;
const fields = item.fields ?? {};

const comments = (fields.comment?.comments ?? []).map(c => ({
  author: c.author?.displayName ?? 'Неизвестно',
  body: c.body,
  created: c.created,
}));

const attachments = (fields.attachment ?? []).map(a => ({
  filename: a.filename,
  mimeType: a.mimeType,
  url: a.content,
}));

return [{
  json: {
    key: item.key,
    summary: fields.summary,
    description: fields.description,
    status: fields.status?.name,
    priority: fields.priority?.name,
    issuetype: fields.issuetype?.name,
    project: fields.project?.name,
    assignee: fields.assignee?.displayName ?? null,
    reporter: fields.reporter?.displayName ?? null,
    labels: fields.labels ?? [],
    created: fields.created,
    updated: fields.updated,
    comments,
    attachments_info: attachments,
    checklists: fields.customfield_19878,
    needToUpdateSource: fields.customfield_19879?.value === 'Да',
    slService: fields.customfield_21219?.[0],
    productCatalog: fields.customfield_22700?.[0],
  },
}];

const query = $json.query ?? {};

let jql;
if (typeof $json.jql === 'string' && $json.jql.trim()) {
  jql = $json.jql.trim();
} else if (query.jql) {
  jql = query.jql;
} else if (query.project) {
  jql = 'project = ' + query.project + ' AND issuetype in ("User Story", Задача, Ошибка, Техдолг, "BUSINESS SUB-TASK", Подзадача) AND status in (Бэклог, Анализ, "Готово к анализу", "Готово к разработке", "Готово к проработке") ORDER BY created ASC';
} else {
  jql = 'project = CREDITS AND issuetype in ("User Story", Задача, Ошибка, Техдолг, "BUSINESS SUB-TASK", Подзадача) AND status in (Бэклог, Анализ, "Готово к анализу", "Готово к разработке", "Готово к проработке") AND labels = Партнерские_Интеграции';
}

return [{ json: { ...$json, jql } }];

const jiraIssues = $('Jira: Get List Issues by JQL').all();
const scoreRows = $('DataTable: RICE Scores').all();
const scoreByKey = new Map(scoreRows.map(({ json }) => [json.key, json]));

return jiraIssues.map(({ json }) => {
  const fields = json.fields ?? {};
  const score = scoreByKey.get(json.key) ?? {};
  const riceScore = score.rice_score ?? null;
  const bugScore = score.bug_score ?? null;
  const tdRoi = score.td_roi ?? null;

  return {
    json: {
      key: json.key ?? 'Неизвестно',
      summary: fields.summary ?? json.summary ?? score.summary ?? '',
      description: fields.description ?? json.description ?? score.description ?? '',
      status: fields.status?.name ?? json.status ?? score.status ?? '',
      priority: fields.priority?.name ?? json.priority ?? score.priority ?? '',
      issuetype: fields.issuetype?.name ?? json.issuetype ?? json.issue_type ?? score.issue_type ?? '',
      reach: score.reach ?? null,
      impact: score.impact ?? null,
      confidence: score.confidence ?? null,
      effort: score.effort ?? null,
      rice_score: riceScore,
      bug_risk: score.bug_risk ?? null,
      bug_process: score.bug_process ?? null,
      bug_scale: score.bug_scale ?? null,
      bug_workaround: score.bug_workaround ?? null,
      bug_score: bugScore,
      td_impact: score.td_impact ?? null,
      td_effort: score.td_effort ?? null,
      td_roi: tdRoi,
      score: riceScore ?? bugScore ?? tdRoi ?? null,
    },
  };
});

const body = $json.body ?? {};

const priorityMap = {
  'Неотложный': '1',
  'Срочный':    '2',
  'Высокий':    '3',
  'Низкий':     '4',
  'Нормальный': '5',
  'Средний':    '10000',
  'Незначительный': '10001',
};

return {
  json: {
    summary:            body.summary,
    description:        body.description,
    issuetype:          body.issuetype,
    priority:           priorityMap[body.priority] ?? body.priority,
    labels:             body.labels,
    slService:          body.slService,
    productCatalog:     body.productCatalog,
    needToUpdateSource: body.needToUpdateSource,
    checklists:         body.checklists,
  },
};

const body  = $json.body ?? {};
const key   = $json.query?.key;

const priorityMap = {
  'Неотложный': '1',
  'Срочный':    '2',
  'Высокий':    '3',
  'Низкий':     '4',
  'Нормальный': '5',
  'Средний':    '10000',
  'Незначительный': '10001',
};

// Собираем только те поля, которые реально пришли в теле запроса
const fields = {
  ...('summary'     in body ? { summary:     body.summary }     : {}),
  ...('description' in body ? { description: body.description } : {}),
  ...('priority'    in body ? { priority: { id: priorityMap[body.priority] ?? body.priority } } : {}),
  ...('labels'      in body ? { labels:       body.labels }      : {}),
  ...('checklists'  in body ? { customfield_19878: Array.isArray(body.checklists) ? body.checklists : [body.checklists] } : {}),
  ...(body.slService          ? { customfield_21219: [body.slService] }                  : {}),
  ...(body.productCatalog     ? { customfield_22700: [body.productCatalog] }             : {}),
  ...(body.needToUpdateSource !== undefined ? { customfield_19879: { value: body.needToUpdateSource || 'Нет' } } : {}),
};

return { json: { key, fields } };

const source = ($json.body && Object.keys($json.body).length ? $json.body : ($json.query ?? {}));
const issueTypes = ['User Story', 'Задача', 'Ошибка', 'Техдолг', 'BUSINESS SUB-TASK', 'Подзадача'];
const statuses = ['Бэклог', 'Анализ', 'Готово к анализу', 'Готово к разработке', 'Готово к проработке'];
const defaultLabel = 'Партнерские_Интеграции';
const project = typeof source.project === 'string' ? source.project.trim() : '';
const customJqlRaw = typeof source.customJql === 'string' ? source.customJql : (typeof source.jql === 'string' ? source.jql : '');
const customJql = customJqlRaw.trim();

let jql;
let cacheKeySource;

if (customJql) {
  jql = customJql;
  cacheKeySource = `jql:${customJql}`;
} else {
  const normalizedProject = project || 'CREDITS';
  const issueTypeClause = issueTypes.map((type) => `"${type}"`).join(', ');
  const statusClause = statuses.map((status) => `"${status}"`).join(', ');
  jql = `project = ${normalizedProject} AND issuetype in (${issueTypeClause}) AND status in (${statusClause}) AND labels = ${defaultLabel} ORDER BY created ASC`;
  cacheKeySource = `project:${normalizedProject}`;
}

return [{ json: { jql, cacheKey: `metrics:${cacheKeySource}`, ttlMs: 10 * 60 * 1000 } }];

const staticData = $getWorkflowStaticData('global');
const key = $json.cacheKey;
const ttlMs = Number($json.ttlMs ?? 600000);
const now = Date.now();
const cached = staticData[key];

if (cached && Array.isArray(cached.issues) && Number(cached.expiresAt) > now) {
  return [{
    json: {
      cacheHit: true,
      issues: cached.issues,
      meta: {
        total: cached.issues.length,
        fetchedAt: cached.fetchedAt,
        cached: true,
        cacheKey: key,
        expiresAt: cached.expiresAt,
      },
    },
  }];
}

return [{ json: { cacheHit: false, jql: $json.jql, cacheKey: key, ttlMs } }];

const cacheInput = $('Code: Metrics Cache Lookup').first().json;
const staticData = $getWorkflowStaticData('global');
const issues = [];

for (const item of $input.all()) {
  const issue = item.json;
  const fields = issue.fields ?? {};
  const histories = Array.isArray(issue.changelog?.histories) ? [...issue.changelog.histories] : [];
  histories.sort((a, b) => new Date(a.created).getTime() - new Date(b.created).getTime());

  const transitions = [];

  const firstStatusHistory = histories.find((history) => Array.isArray(history.items) && history.items.some((change) => change.field === 'status'));
  if (firstStatusHistory) {
    const firstStatusChange = firstStatusHistory.items.find((change) => change.field === 'status');
    if (firstStatusChange?.fromString) {
      transitions.push({
        to: firstStatusChange.fromString,
        date: fields.created,
      });
    }
  }

  for (const history of histories) {
    for (const change of history.items ?? []) {
      if (change.field !== 'status' || !change.toString || !history.created) continue;
      transitions.push({
        to: change.toString,
        date: history.created,
        from: change.fromString ?? undefined,
      });
    }
  }

  issues.push({
    key: issue.key,
    summary: fields.summary ?? '',
    type: fields.issuetype?.name ?? 'Unknown',
    created: fields.created ?? '',
    currentStatus: fields.status?.name ?? '',
    transitions,
  });
}

const fetchedAt = new Date().toISOString();
const expiresAt = Date.now() + Number(cacheInput.ttlMs ?? 600000);
staticData[cacheInput.cacheKey] = { issues, fetchedAt, expiresAt };

return [{
  json: {
    issues,
    meta: {
      total: issues.length,
      fetchedAt,
      cached: false,
      cacheKey: cacheInput.cacheKey,
      expiresAt,
    },
  },
}];

const query = $json.query ?? {};
const refreshRaw = String(query.refresh ?? '').trim().toLowerCase();
const refreshRequested = ['1', 'true', 'yes'].includes(refreshRaw);
const project = typeof query.project === 'string' ? query.project.trim() : '';
const customJql = typeof query.jql === 'string' ? query.jql.trim() : '';

return [{
  json: {
    query,
    project,
    customJql,
    refreshRequested,
  },
}];

const issues = $input.all().map(({ json }) => json);
return [{
  json: {
    issues,
    meta: {
      fetchedAt: new Date().toISOString(),
      cached: false,
      source: 'jira+datatable',
    },
  },
}];

const query = $json.query ?? {};

let jql;
if (typeof $json.jql === 'string' && $json.jql.trim()) {
  jql = $json.jql.trim();
} else if (query.jql) {
  jql = query.jql;
} else if (query.project) {
  jql = 'project = ' + query.project + ' AND issuetype in ("User Story", Задача, Ошибка, Техдолг, "BUSINESS SUB-TASK", Подзадача) AND status in (Бэклог, Анализ, "Готово к анализу", "Готово к разработке", "Готово к проработке") ORDER BY created ASC';
} else {
  jql = 'project = CREDITS AND issuetype in ("User Story", Задача, Ошибка, Техдолг, "BUSINESS SUB-TASK", Подзадача) AND status in (Бэклог, Анализ, "Готово к анализу", "Готово к разработке", "Готово к проработке") AND labels = Партнерские_Интеграции';
}

return [{ json: { ...$json, jql } }];

const jiraIssues = $('Jira: Refresh List Issues by JQL').all();
const scoreRows = $('DataTable: Get Refreshed Scores').all();
const scoreByKey = new Map(scoreRows.map(({ json }) => [json.key, json]));
const now = new Date().toISOString();

const issues = jiraIssues.map(({ json }) => {
  const fields = json.fields ?? {};
  const score = scoreByKey.get(json.key) ?? {};
  const riceScore = score.rice_score ?? null;
  const bugScore = score.bug_score ?? null;
  const tdRoi = score.td_roi ?? null;

  return {
    key: json.key ?? 'Неизвестно',
    summary: fields.summary ?? json.summary ?? score.summary ?? '',
    description: fields.description ?? json.description ?? score.description ?? '',
    status: fields.status?.name ?? json.status ?? score.status ?? '',
    priority: fields.priority?.name ?? json.priority ?? score.priority ?? '',
    issuetype: fields.issuetype?.name ?? json.issuetype ?? json.issue_type ?? score.issue_type ?? '',
    reach: score.reach ?? null,
    impact: score.impact ?? null,
    confidence: score.confidence ?? null,
    effort: score.effort ?? null,
    rice_score: riceScore,
    bug_risk: score.bug_risk ?? null,
    bug_process: score.bug_process ?? null,
    bug_scale: score.bug_scale ?? null,
    bug_workaround: score.bug_workaround ?? null,
    bug_score: bugScore,
    td_impact: score.td_impact ?? null,
    td_effort: score.td_effort ?? null,
    td_roi: tdRoi,
    score: riceScore ?? bugScore ?? tdRoi ?? null,
  };
});

return [{
  json: {
    issues,
    meta: {
      fetchedAt: now,
      syncedAt: now,
      cached: false,
      source: 'jira-refresh+datatable',
    },
  },
}];

const source = $json.body ?? {};
if (!Array.isArray(source.updates)) {
  return [{
    json: {
      valid: false,
      error: 'Expected body.updates to be an array',
      skipped: [],
      updates: [],
    },
  }];
}

const numericFields = [
  'reach', 'impact', 'confidence', 'effort', 'rice_score',
  'bug_risk', 'bug_process', 'bug_scale', 'bug_workaround', 'bug_score',
  'td_impact', 'td_effort', 'td_roi',
];

const updates = [];
const skipped = [];

for (const raw of source.updates) {
  if (!raw || typeof raw !== 'object') {
    skipped.push({ key: '', reason: 'Invalid update item' });
    continue;
  }

  const key = typeof raw.key === 'string' ? raw.key.trim() : '';
  if (!key) {
    skipped.push({ key: '', reason: 'Missing key' });
    continue;
  }

  const normalized = { key };
  for (const field of numericFields) {
    const value = raw[field];
    normalized[field] = typeof value === 'number' && Number.isFinite(value) ? value : null;
  }
  updates.push(normalized);
}

if (!updates.length) {
  return [{
    json: {
      valid: false,
      error: skipped.length ? 'No valid updates provided' : 'No updates provided',
      skipped,
      updates: [],
    },
  }];
}

return [{ json: { valid: true, updates, skipped } }];

const existingRows = $('DataTable: Existing Score Rows').all();
const existingKeys = new Set(existingRows.map(({ json }) => json.key).filter((key) => typeof key === 'string' && key));
const payload = $('Code: Validate Scoring Updates').first().json;
const created = [];
const updated = [];

for (const item of payload.updates ?? []) {
  if (!item?.key) continue;
  if (existingKeys.has(item.key)) updated.push(item.key);
  else created.push(item.key);
}

return [{
  json: {
    updated,
    created,
    skipped: payload.skipped ?? [],
    meta: {
      savedAt: new Date().toISOString(),
      source: 'jira-issues-scoring',
    },
  },
}];

return [{
  json: {
    error: $json.error ?? 'Invalid scoring payload',
    skipped: $json.skipped ?? [],
    meta: {
      savedAt: new Date().toISOString(),
      source: 'jira-issues-scoring',
    },
  },
}];
